enum OrderStatus {
  Pending   = "PENDING",
  Processing= "PROCESSING",
  Shipped   = "SHIPPED",
  Delivered = "DELIVERED",
  Cancelled = "CANCELLED",
}

function describe(status: OrderStatus): string {
  switch (status) {
    case OrderStatus.Pending:    return "Awaiting confirmation";
    case OrderStatus.Processing: return "Being prepared";
    case OrderStatus.Shipped:    return "On the way";
    case OrderStatus.Delivered:  return "Delivered!";
    case OrderStatus.Cancelled:  return "Cancelled";
  }
}

const statuses: OrderStatus[] = [
  OrderStatus.Pending,
  OrderStatus.Processing,
  OrderStatus.Shipped,
];

for (const s of statuses) {
  console.log(`${s}: ${describe(s)}`);
}

enum LogLevel {
  Debug   = 0,
  Info    = 1,
  Warning = 2,
  Error   = 3,
  Fatal   = 4,
}

let currentLevel = LogLevel.Info;

function log(level: LogLevel, message: string): void {
  if (level >= currentLevel) {
    const label = LogLevel[level];  // reverse mapping
    console.log(`[${label}] ${message}`);
  }
}

log(LogLevel.Debug,   "Variable x = 42");       // filtered
log(LogLevel.Info,    "Server started");
log(LogLevel.Warning, "High memory usage");
log(LogLevel.Error,   "Database timeout");

const enum HttpStatus {
  OK        = 200,
  Created   = 201,
  NoContent = 204,
  BadReq    = 400,
  NotFound  = 404,
  ServerErr = 500,
}

function handleResponse(status: HttpStatus): string {
  if (status >= 200 && status < 300) return "Success";
  if (status >= 400 && status < 500) return "Client error";
  return "Server error";
}

console.log(`200: ${handleResponse(HttpStatus.OK)}`);
console.log(`201: ${handleResponse(HttpStatus.Created)}`);
console.log(`404: ${handleResponse(HttpStatus.NotFound)}`);
console.log(`500: ${handleResponse(HttpStatus.ServerErr)}`);

// Approach 1: Enum
enum DirectionEnum {
  North = "NORTH",
  South = "SOUTH",
  East  = "EAST",
  West  = "WEST",
}

// Approach 2: Union type (preferred by many teams)
type Direction = "NORTH" | "SOUTH" | "EAST" | "WEST";

// Both work identically for type checking
function moveEnum(dir: DirectionEnum): string {
  return `Moving ${dir} (enum)`;
}

function moveUnion(dir: Direction): string {
  return `Moving ${dir} (union)`;
}

console.log(moveEnum(DirectionEnum.North));
console.log(moveUnion("NORTH"));

