enum Permission {
  None    = 0,
  Read    = 1 << 0,  // 1
  Write   = 1 << 1,  // 2
  Execute = 1 << 2,  // 4
  Admin   = Read | Write | Execute,  // 7
}

function hasPermission(userPerms: Permission, check: Permission): boolean {
  return (userPerms & check) === check;
}

function describePermissions(perms: Permission): string {
  const parts: string[] = [];
  if (hasPermission(perms, Permission.Read))    parts.push("read");
  if (hasPermission(perms, Permission.Write))   parts.push("write");
  if (hasPermission(perms, Permission.Execute)) parts.push("execute");
  return parts.join(", ") || "none";
}

const viewer = Permission.Read;
const editor = Permission.Read | Permission.Write;
const admin  = Permission.Admin;

console.log(`Viewer (${viewer}): ${describePermissions(viewer)}`);
console.log(`Editor (${editor}): ${describePermissions(editor)}`);
console.log(`Admin  (${admin}): ${describePermissions(admin)}`);
console.log(`Editor can write: ${hasPermission(editor, Permission.Write)}`);

enum Weekday {
  Monday    = 1,
  Tuesday   = 2,
  Wednesday = 3,
  Thursday  = 4,
  Friday    = 5,
}

// Get only the string keys (filter out reverse-mapped numeric keys)
const weekdays = Object.values(Weekday)
  .filter((v): v is Weekday => typeof v === "number") as Weekday[];

for (const day of weekdays) {
  const name = Weekday[day];  // reverse mapping
  const isHumpDay = day === Weekday.Wednesday;
  console.log(`${name} (${day})${isHumpDay ? " 🐪" : ""}`);
}

