class User {
  static readonly Status = {
    Active:    "active",
    Suspended: "suspended",
    Deleted:   "deleted",
  } as const;

  type Status = typeof User.Status[keyof typeof User.Status];

  constructor(
    public readonly id: number,
    public readonly name: string,
    public status: string = User.Status.Active
  ) {}

  suspend(): void {
    this.status = User.Status.Suspended;
  }

  describe(): string {
    return `${this.name} [${this.status}]`;
  }
}

const alice = new User(1, "Alice");
const bob   = new User(2, "Bob");

console.log(alice.describe());
bob.suspend();
console.log(bob.describe());
console.log(`Alice active: ${alice.status === User.Status.Active}`);

enum ActionType {
  Increment = "INCREMENT",
  Decrement = "DECREMENT",
  Reset     = "RESET",
  SetValue  = "SET_VALUE",
}

interface Action {
  type: ActionType;
  payload?: number;
}

function reducer(state: number, action: Action): number {
  switch (action.type) {
    case ActionType.Increment: return state + 1;
    case ActionType.Decrement: return state - 1;
    case ActionType.Reset:     return 0;
    case ActionType.SetValue:  return action.payload ?? state;
    default: {
      // This would error if a new ActionType was added but not handled
      const exhaustive: never = action.type;
      return state;
    }
  }
}

const actions: Action[] = [
  { type: ActionType.SetValue, payload: 10 },
  { type: ActionType.Increment },
  { type: ActionType.Increment },
  { type: ActionType.Decrement },
  { type: ActionType.Reset },
];

let count = 0;
for (const action of actions) {
  count = reducer(count, action);
  console.log(`${action.type} → ${count}`);
}

