enum NotificationType {
  Success = "success",
  Warning = "warning",
  Error   = "error",
  Info    = "info",
}

const notificationStyles: Record<NotificationType, { icon: string; color: string }> = {
  [NotificationType.Success]: { icon: "✅", color: "green"  },
  [NotificationType.Warning]: { icon: "⚠️", color: "amber"  },
  [NotificationType.Error]:   { icon: "❌", color: "red"    },
  [NotificationType.Info]:    { icon: "ℹ️", color: "blue"   },
};

function showNotification(type: NotificationType, message: string): void {
  const style = notificationStyles[type];
  console.log(`${style.icon} [${style.color.toUpperCase()}] ${message}`);
}

showNotification(NotificationType.Success, "File uploaded successfully");
showNotification(NotificationType.Warning, "Storage at 80% capacity");
showNotification(NotificationType.Error,   "Connection failed");
showNotification(NotificationType.Info,    "New version available");
